sql:
SELECT event_type, description
FROM roadside_events
WHERE severity IN ('High', 'Medium');

SELECT COUNT(*) AS accident_count
FROM roadside_events
WHERE event_type = 'accident' AND month = 5;

SELECT MAX(severity) AS max_severity
FROM roadside_events
WHERE region_id = 1;

SELECT COUNT(*) AS resolved_violations_count
   FROM roadside_event_violations
   WHERE violation_status = 'Resolved';

SELECT weight
FROM severity_weights
WHERE region_id = 1;

SELECT violation_type, COUNT(*) AS violation_count
FROM roadside_event_violations
GROUP BY violation_type;

SELECT event_id, SUM(number_of_vehicles_involved) AS total_vehicles_involved
FROM roadside_events
GROUP BY event_id;

SELECT violation_type 
FROM roadside_event_violations 
WHERE violation_status = 'Resolved';

SELECT event_type, SUM(number_of_injuries) AS total_injuries
FROM roadside_events
GROUP BY event_type;

external_knowledge:
; The "most severe events" refers to those with the highest weighted severity scores; 
; The cumulative severity score is calculated based on the weighted severity of each event; 
; The weighted severity is determined by multiplying the event's severity with its corresponding weight.

